import { Filesystem, Directory, Encoding } from '@capacitor/filesystem';

const writeBtn = document.getElementById('write-btn') as HTMLButtonElement | null;
const readBtn = document.getElementById('read-btn') as HTMLButtonElement | null;
const fileContent = document.getElementById('file-content') as HTMLSpanElement | null;

if (writeBtn && readBtn && fileContent) {
  writeBtn.addEventListener('click', async () => {
    await Filesystem.writeFile({
      path: 'demo.txt',
      data: 'Hello Capacitor',
      directory: Directory.Data,
      encoding: Encoding.UTF8,
    });
  });

  readBtn.addEventListener('click', async () => {
    const result = await Filesystem.readFile({
      path: 'demo.txt',
      directory: Directory.Data,
      encoding: Encoding.UTF8,
    });
    fileContent.textContent = result.data as string;
  });
}

// Verify that the Capacitor Filesystem web implementation works correctly.
// This simulates what happens in the browser by using the same IndexedDB-backed
// filesystem that the plugin exposes on the web platform.

import { Filesystem, Directory, Encoding } from '@capacitor/filesystem';

async function main() {
  // Write the file
  await Filesystem.writeFile({
    path: 'demo.txt',
    data: 'Hello Capacitor',
    directory: Directory.Data,
    encoding: Encoding.UTF8,
  });
  console.log('Write OK');

  // Read it back
  const result = await Filesystem.readFile({
    path: 'demo.txt',
    directory: Directory.Data,
    encoding: Encoding.UTF8,
  });
  console.log('Read result:', JSON.stringify(result.data));
  console.log('Matches expected:', result.data === 'Hello Capacitor' ? 'YES' : 'NO');

  // Verify the data
  if (result.data === 'Hello Capacitor') {
    console.log('SUCCESS: Filesystem write/read works correctly.');
    process.exit(0);
  } else {
    console.log('FAILURE: Data mismatch.');
    process.exit(1);
  }
}

main().catch((err) => {
  console.error('ERROR:', err);
  process.exit(1);
});
